import React, { useState, useEffect } from "react";
import { useAuth } from "../contexts/AuthContext";
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from "recharts";
import api from "../api/api";

const MOCK_TREND = [
  {date:"Jan 10",units:420},{date:"Jan 13",units:380},{date:"Jan 16",units:510},
  {date:"Jan 19",units:490},{date:"Jan 22",units:560},{date:"Jan 25",units:530},
  {date:"Jan 28",units:610},{date:"Jan 31",units:590},{date:"Feb 3",units:650},
  {date:"Feb 6",units:620},{date:"Feb 9",units:700},{date:"Feb 12",units:680},
  {date:"Feb 15",units:730},{date:"Feb 18",units:760},
];

const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{background:"white",border:"1px solid var(--border)",borderRadius:10,padding:"10px 14px",fontSize:13}}>
      <div style={{color:"var(--muted)",marginBottom:4}}>{label}</div>
      <div style={{fontWeight:700,color:"var(--accent)"}}>{payload[0].value.toLocaleString()} units</div>
    </div>
  );
};

export default function DashboardPage() {
  const { manufacturer } = useAuth();
  const [stats, setStats] = useState(null);
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const [sRes, pRes] = await Promise.allSettled([
          api.get("/manufacturer/dashboard-stats"),
          api.get("/manufacturer/products"),
        ]);
        if (sRes.status === "fulfilled") setStats(sRes.value.data);
        if (pRes.status === "fulfilled") setProducts(pRes.value.data?.products || []);
      } catch(_) {}
      finally { setLoading(false); }
    };
    load();
  }, []);

  const displayStats = stats || {
    total_products: products.length || 0,
    total_units_sold: 14820,
    active_regions: 6,
    avg_stockout_risk: "Medium",
  };

  const topProducts = [
    { name: "Maggi 2-Minute Masala Noodles 280g", units: 3240, share: 88 },
    { name: "Coca-Cola 600ml",                    units: 2810, share: 76 },
    { name: "Bisleri Water 500ml",                units: 2460, share: 67 },
    { name: "Brooke Bond Red Label Tea 500g",     units: 1920, share: 52 },
    { name: "Nescafe Classic Coffee 90g",         units: 1540, share: 42 },
  ];

  const regionSplit = [
    { state:"Kerala",     stores:18, share:72 },
    { state:"Karnataka",  stores:12, share:48 },
    { state:"Tamil Nadu", stores:9,  share:36 },
    { state:"Telangana",  stores:6,  share:24 },
  ];

  return (
    <>
      <div className="page-header">
        <div className="page-title">
          Good {new Date().getHours()<12?"morning":new Date().getHours()<18?"afternoon":"evening"},{" "}
          {manufacturer?.company_name?.split(" ")[0] || "there"} 👋
        </div>
        <div className="page-sub">Here's how your products are performing across the Reco network</div>
      </div>

      <div className="grid-4" style={{marginBottom:24}}>
        {[
          { label:"Listed products",   value: displayStats.total_products || products.length || "—", sub:"In the Reco catalog" },
          { label:"Units sold",        value: (14820).toLocaleString(), sub:"Last 30 days", badge:"up", badgeTxt:"↑ 12%" },
          { label:"Active regions",    value: displayStats.active_regions || 6, sub:"States with stores" },
          { label:"Avg stockout risk", value: displayStats.avg_stockout_risk || "Medium", sub:"Across network", riskColor:"var(--warn)" },
        ].map((s,i)=>(
          <div className="card card-sm" key={i}>
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={s.riskColor?{fontSize:22,color:s.riskColor}:{}}>{s.value}</div>
            {s.badge && <div className={`stat-badge ${s.badge}`}>{s.badgeTxt}</div>}
            <div className="stat-sub">{s.sub}</div>
          </div>
        ))}
      </div>

      <div className="grid-2" style={{marginBottom:24}}>
        <div className="card">
          <div className="section-head">
            <div>
              <div className="section-title">Sales Trend</div>
              <div className="section-sub">Units sold across all stores · Jan–Feb 2026</div>
            </div>
          </div>
          <ResponsiveContainer width="100%" height={180}>
            <LineChart data={MOCK_TREND} margin={{left:-20,right:0,top:4,bottom:0}}>
              <CartesianGrid stroke="var(--border)" strokeDasharray="0" vertical={false}/>
              <XAxis dataKey="date" tick={{fontSize:10,fill:"var(--muted)"}} axisLine={false} tickLine={false} interval={2}/>
              <YAxis tick={{fontSize:10,fill:"var(--muted)"}} axisLine={false} tickLine={false}/>
              <Tooltip content={<CustomTooltip/>}/>
              <Line type="monotone" dataKey="units" stroke="var(--accent)" strokeWidth={2.5} dot={false} activeDot={{r:4}}/>
            </LineChart>
          </ResponsiveContainer>
        </div>

        <div className="card">
          <div className="section-head">
            <div className="section-title">Regional Spread</div>
            <div className="section-sub">Store coverage</div>
          </div>
          {regionSplit.map((r,i)=>(
            <div className="region-row" key={i}>
              <div className="region-name">{r.state}</div>
              <div className="region-bar-wrap">
                <div className="progress-bar">
                  <div className="progress-fill" style={{width:`${r.share}%`,
                    background:i===0?"var(--accent)":i===1?"#6B8EF9":i===2?"#9DB3FB":"#C5D2FD"}}/>
                </div>
              </div>
              <div className="region-count">{r.stores} stores</div>
            </div>
          ))}
        </div>
      </div>

      <div className="card">
        <div className="section-head">
          <div className="section-title">Top Performing Products</div>
          <div className="section-sub">By units sold · last 30 days</div>
        </div>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>#</th>
                <th>Product</th>
                <th>Units sold</th>
                <th>Network coverage</th>
              </tr>
            </thead>
            <tbody>
              {topProducts.map((p,i)=>(
                <tr key={i}>
                  <td style={{color:"var(--muted)",fontWeight:700,width:32}}>{i+1}</td>
                  <td style={{fontWeight:500}}>{p.name}</td>
                  <td><span style={{fontWeight:700}}>{p.units.toLocaleString()}</span></td>
                  <td style={{width:200}}>
                    <div style={{display:"flex",alignItems:"center",gap:10}}>
                      <div className="progress-bar" style={{flex:1}}>
                        <div className="progress-fill" style={{width:`${p.share}%`}}/>
                      </div>
                      <span style={{fontSize:12,color:"var(--muted)",width:32}}>{p.share}%</span>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </>
  );
}
